```class Solution {
    public int getKth(int lo, int hi, int k) {
        int[] powers = new int[hi - lo + 1];
        for (int i = lo; i <= hi; i++) {
            int power = 0;
            int x = i;
            while (x != 1) {
                if (x % 2 == 0) {
                    x /= 2;
                } else {
                    x = 3 * x + 1;
                }
                power++;
            }
            powers[i - lo] = power;
        }
        Arrays.sort(powers);
        for (int i = 0; i < powers.length; i++) {
            if (k == 1) {
                return lo + i;
            }
            k--;
        }
        return lo + powers.length - 1;
    }
}```
